parameters.jsCode:
const item = $input.first().json;
const sampleQuestions = [
  "Do you encrypt customer data at rest?",
  "Do you support SSO with SAML?",
  "How do you manage access to production systems?",
  "Do you have an incident response process?",
  "Where is customer data hosted?"
];

return [{
  json: {
    config: {
      notion_database_id: item.notion_database_id,
      google_drive_folder_id: item.google_drive_folder_id,
      google_doc_template_id: item.google_doc_template_id,
      review_slack_channel_id: item.review_slack_channel_id,
      minimum_match_confidence: Number(item.minimum_match_confidence || 0.7),
      approved_answer_status: item.approved_answer_status,
      questionnaire_customer_name: item.questionnaire_customer_name,
      security_reviewer_email: item.security_reviewer_email,
      notion_questionnaire_tracker_id: item.notion_questionnaire_tracker_id,
    },
    questions: sampleQuestions.map((question, index) => ({ id: index + 1, question }))
  }
}];

// Replace the sample answer library with the Notion response after testing.
// This deterministic matcher avoids invented answers and marks low-confidence matches for review.
const input = $input.first().json;
const cfg = input.config || $('Prepare Questionnaire Questions').first().json.config;
const questions = input.questions || $('Prepare Questionnaire Questions').first().json.questions;

const approvedAnswers = [
  {
    category: 'Data protection',
    question: 'Do you encrypt customer data at rest?',
    answer: 'Yes. Customer data is encrypted at rest using managed cloud encryption controls. Confirm exact algorithms and key management details during review.',
    owner: 'Security'
  },
  {
    category: 'Identity and access',
    question: 'Do you support SSO with SAML?',
    answer: 'Yes. SAML SSO is supported for eligible plans. Confirm IdP-specific instructions with the implementation team.',
    owner: 'Product'
  },
  {
    category: 'Access management',
    question: 'How do you manage access to production systems?',
    answer: 'Production access is restricted to authorized personnel and reviewed periodically. Add your internal review cadence before sending.',
    owner: 'Security'
  },
  {
    category: 'Incident response',
    question: 'Do you have an incident response process?',
    answer: 'Yes. The company maintains an incident response process with defined triage, escalation, communication, and post-incident review steps.',
    owner: 'Security'
  }
];

function tokenize(s) {
  return new Set(String(s).toLowerCase().replace(/[^a-z0-9\s]/g, ' ').split(/\s+/).filter(w => w.length > 2));
}
function jaccard(a, b) {
  const A = tokenize(a), B = tokenize(b);
  const inter = [...A].filter(x => B.has(x)).length;
  const union = new Set([...A, ...B]).size || 1;
  return inter / union;
}

const matched = questions.map(q => {
  let best = null;
  let score = 0;
  for (const a of approvedAnswers) {
    const s = jaccard(q.question, a.question);
    if (s > score) { score = s; best = a; }
  }
  const approved = best && score >= cfg.minimum_match_confidence;
  return {
    id: q.id,
    question: q.question,
    answer: approved ? best.answer : 'Needs review',
    category: approved ? best.category : 'Unmatched',
    owner: approved ? best.owner : cfg.security_reviewer_email,
    confidence: Number(score.toFixed(2)),
    needsReview: !approved
  };
});

return [{
  json: {
    config: cfg,
    matchedAnswers: matched,
    needsReviewCount: matched.filter(x => x.needsReview).length,
    totalQuestions: matched.length
  }
}];

const data = $input.first().json;
const cfg = data.config;
const lines = [];
lines.push(`# Security questionnaire draft - ${cfg.questionnaire_customer_name}`);
lines.push('');
lines.push('Review all answers before sending this document externally.');
lines.push('');
for (const item of data.matchedAnswers) {
  lines.push(`## ${item.id}. ${item.question}`);
  lines.push(`Category: ${item.category}`);
  lines.push(`Owner: ${item.owner}`);
  lines.push(`Confidence: ${item.confidence}`);
  lines.push('');
  lines.push(item.answer);
  lines.push('');
  if (item.needsReview) lines.push('Reviewer note: This answer needs manual review before submission.\n');
}
return [{ json: { ...data, documentMarkdown: lines.join('\n') } }];

